          0
        );
        const ticketAmount = (request.eventTicketsAttributes ?? []).reduce(
          (acc, { price }) => acc + price,
          0
        );
        const totalAmount = donationAmount + ticketAmount;

        let multiplier = 1;
        if (frequency === SourceFrequency.Monthly) {
          multiplier = 12;
        } else if (frequency === SourceFrequency.Weekly) {
          multiplier = 52;
        } else if (frequency === SourceFrequency.Quarterly) {
          multiplier = 4;
        } else if (frequency === SourceFrequency.Daily) {
          multiplier = 365;
        }

