          ...submissionInner,
          amountAllocationsAttributes: submissionAmountAllocationsAttributes,
          ddcSessionId,
          scheduleAttributes,
          submissionPaymentMethodAttributes,
        },
        type: submissionType,
      } as ActionPageSubmissionRequest;

      const onError = (response: IErrorResponse) => {
        const message = formatSubmissionErrorMessage(
          response as { response?: { status: number } },
          t
        );

        showToast({
          message,
          variant: 'error',
        });

        resetTurnstile();

        form?.trigger();

        const e = {
          cause: response,
          message: 'Unable to complete submission',
          name: 'SubmissionError',
        };

        console.error(e);
        rollbar.error(e);
      };

      const onSuccess = async (response: PublicSubmission) => {
        // hide express checkout controls through the chain if necessary
        // If they used express checkout, we should show the controls on the
        // next upgrade
        trackSubmission(
          {
            ...submission,
            actionPageId,
            hasValidUpgradePaymentMethod:
              hasValidUpgradePaymentMethod || isDonationPage(submission.pageType),
            hideExpressCheckoutControls:
              submission.hideExpressCheckoutControls ||
              (submission.type !== 'lead' && !expressCheckoutMethod) ||
              expressCheckoutMethod === 'googlepay',
            submissionPaymentMethodAttributes:
              actionPageSubmission.submission.submissionPaymentMethodAttributes,
          },
          response,
          type !== 'bitcoin_open_node' && (pageType as string) !== 'storefront', // skip upgrade workflow if storefront or payment type is bitcoin
          type !== 'bitcoin_open_node' // only show receipt if not bitcoin
        );

        if (type === 'bitcoin_open_node') {
          try {
            const publicSubmission = await getPublicSubmission({ submissionId: response.id });
            // Union type apparently fails here
            // @ts-ignore
            const { hostedCheckoutUrl } = publicSubmission?.paymentMethod?.metadata || {};

            if (hostedCheckoutUrl) {
              window.location.assign(hostedCheckoutUrl);
            }
          } catch (_err) {
            console.warn('Unable to retrieve OpenNode callback URL');
          }
        }
      };

      if (
        eventTicketsAttributes &&
        /**
         * Ensure the Event doesn't get submitted repeatedly during Upgrade workflows
         */
        !transactionPairs.some((txPair) => txPair?.request?.eventTicketsAttributes)
      ) {
        const eventPageSubmission = {
          submission: {
            ...submissionInner,
            amountAllocationsAttributes: submissionAmountAllocationsAttributes,
            ddcSessionId,
            eventTicketsAttributes,
            promoCodeId: promoCodeAttributes?.id,
            scheduleAttributes,
            submissionPaymentMethodAttributes,
          },
          // Only use auth capture less than $500 and the feature is enabled
          type: pageType,
        } as ActionPageSubmissionRequest;
